import { describe, expect, it } from "vitest";
import { buildExperimentsPath, buildExperimentsPathForDataset, buildExperimentsPathForGroup, parseTestRunIds, } from "./openExperiments.js";
const A = "aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa";
const B = "bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb";
const C = "cccccccc-cccc-cccc-cccc-cccccccccccc";
describe("parseTestRunIds", () => {
    it("returns ids from a single comma-separated arg", () => {
        expect(parseTestRunIds([`${A},${B}`])).toEqual([A, B]);
    });
    it("returns ids from multiple separate args", () => {
        expect(parseTestRunIds([A, B, C])).toEqual([A, B, C]);
    });
    it("handles a mix of comma-separated and separate args", () => {
        expect(parseTestRunIds([`${A},${B}`, C])).toEqual([A, B, C]);
    });
    it("trims whitespace around each id", () => {
        expect(parseTestRunIds([` ${A} , ${B} `])).toEqual([A, B]);
    });
    it("deduplicates ids (case-insensitive)", () => {
        expect(parseTestRunIds([A, A.toUpperCase()])).toEqual([A]);
    });
    it("filters out non-UUIDs silently", () => {
        expect(parseTestRunIds([A, "not-a-uuid", "", B])).toEqual([A, B]);
    });
    it("returns an empty array when no valid ids are present", () => {
        expect(parseTestRunIds(["not-a-uuid", ""])).toEqual([]);
        expect(parseTestRunIds([])).toEqual([]);
    });
});
describe("buildExperimentsPath", () => {
    it("builds the path with comma-joined ids", () => {
        expect(buildExperimentsPath([A, B])).toBe(`/studio/experiments?testRunIds=${A}%2C${B}`);
    });
    it("works with a single id", () => {
        expect(buildExperimentsPath([A])).toBe(`/studio/experiments?testRunIds=${A}`);
    });
});
describe("buildExperimentsPathForGroup", () => {
    it("builds the path with experimentGroupId", () => {
        expect(buildExperimentsPathForGroup(A)).toBe(`/studio/experiments?experimentGroupId=${A}`);
    });
});
describe("buildExperimentsPathForDataset", () => {
    it("builds the path with datasetId", () => {
        expect(buildExperimentsPathForDataset(A)).toBe(`/studio/experiments?datasetId=${A}`);
    });
});
